#include <bits/stdc++.h>
using namespace std;

const int N=1e4+4;

int n,p,ans[N];
bool b[N];
char s[N];

int main(){
    scanf("%d%s%d",&n,s+1,&p);
    for(int i=n;i;i--){
        int sum=1;
        for(int j=1;j<=n;j++)
            if(s[j]<s[p] || (s[j]==s[p] && !b[j] && i<n))
                sum++;
        b[sum]=1,ans[i]=sum,p=sum;
    }
    for(int i=1;i<=n;i++)
        printf("%c",s[ans[i]]);
    return 0;
}
